import {
  createContext,
  type AnchorHTMLAttributes,
  type Ref,
  type Context,
} from 'react';

import type { AriaButtonProps, ButtonAria } from '../../../../buttons/button/types/button-aria.js';
import type { AriaLabelingProps } from '../../../../core/types/a11y-props.js';

/** @internal */
export interface SegmentsTriggerContextProps extends AriaLabelingProps {
  /** Element displayed in the trigger of the segments selector */
  displayValue: string | null;
  /** Whether the element is loading. */
  isLoading: boolean;
  /** Necessary props for the trigger. */
  triggerProps:
    | (Partial<ButtonAria<AnchorHTMLAttributes<HTMLButtonElement>>> &
        AriaButtonProps)
    | null;
  /** Ref of the trigger button. */
  buttonRef: Ref<HTMLButtonElement>;
  /** Whether the SegmentSelector shows an error. */
  showError?: boolean;
}

/**
 * SegmentSelector trigger context, used to access the trigger props.
 * @internal
 */
export const SegmentsTriggerContext: Context<SegmentsTriggerContextProps> =
  createContext<SegmentsTriggerContextProps>({
    displayValue: null,
    isLoading: true,
    triggerProps: null,
    buttonRef: null,
  });
